            db.rm('key1', function() {
                assert.strictEqual(db.get('key1'), undefined);
                assert.strictEqual(db.size(), 0);
                done();
            });
        });
    });

    it('should iterate over keys with forEach', function(done) {
        const db = new dirty.Dirty();

        db.on('load', function() {
            db.set('key1', {value: 1});
            db.set('key2', {value: 2});

            const found = [];
            db.forEach(function(key, val) {
                found.push({key, val});
            });

            assert.strictEqual(found.length, 2);
            assert.strictEqual(found.some(item => item.key === 'key1' && item.val.value === 1), true);
            assert.strictEqual(found.some(item => item.key === 'key2' && item.val.value === 2), true);
            done();
        });
    });

    it('should update values using update method', function(done) {
        const db = new dirty.Dirty();

        db.on('load', function() {
            db.set('counter', {count: 5});

            db.update('counter', function(val) {
                return {count: val.count + 1};
            }, function() {
                const result = db.get('counter');
                assert.deepStrictEqual(result, {count: 6});
                done();
            });
        });
    });

    it('should persist data to disk and load it back', function(done) {
        const db1 = new dirty.Dirty(dbPath);

        db1.on('load', function() {
            db1.set('persistent', {data: 'test'}, function() {
                db1.close();

                // Create new instance to test loading
                const db2 = new dirty.Dirty(dbPath);
                db2.on('load', function(length) {
                    assert.strictEqual(length, 1);
                    const result = db2.get('persistent');
                    assert.deepStrictEqual(result, {data: 'test'});
                    db2.close();
                    done();
                });
            });
        });
    });

    it('should emit drain event when all writes are complete', function(done) {
        const db = new dirty.Dirty(dbPath);

        db.on('load', function() {
            db.set('key1', {value: 1});
            db.set('key2', {value: 2});

            db.on('drain', function() {
                assert.strictEqual(db.size(), 2);
                db.close();
                done();
            });
        });
    });

    it('should handle non-existent file gracefully', function(done) {
        const nonExistentPath = path.join(tempDir, 'does-not-exist.db');
        const db = new dirty.Dirty(nonExistentPath);

        db.on('load', function(length) {
            assert.strictEqual(length, 0);
            assert.strictEqual(db.size(), 0);
            db.close();
            done();
        });
    });
});
